/*
 * log1p() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly log1p   (test_log1p_opt.elf)
 *   2. Linked with toolchain's default log1p        (test_log1p_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += log1p(vx);
#else
    double r = log1p(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 hand-picked inputs for log1p()        */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (8) --- */
    emit(0.0);                                   /* log1p(0) = 0 */
    emit(-0.0);                                  /* log1p(-0) = -0 */
    emit_u(0x7ff8000000000000ULL);               /* qNaN */
    emit_u(0x7ff0000000000001ULL);               /* sNaN */
    emit_u(0xfff8000000000000ULL);               /* -qNaN */
    emit_u(0x7ff0000000000000ULL);               /* +Inf: log1p(+Inf) = +Inf */
    emit_u(0xfff0000000000000ULL);               /* -Inf: log1p(-Inf) = NaN (domain error) */
    emit(-1.0);                                  /* -1.0 exactly: log1p(-1) = -Inf */

    /* --- Section 2: Domain error region x < -1 (5) --- */
    emit(-2.0);                                  /* x < -1: NaN */
    emit(-1.5);                                  /* x < -1: NaN */
    emit_u(0xbff0000000000001ULL);               /* -1.0 - 1 ULP (just below -1): NaN */
    emit(-1.0e10);                               /* large negative: NaN */
    emit(-DBL_MAX);                              /* most negative finite: NaN */

    /* --- Section 3: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);               /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);               /* min negative subnormal */
    emit_u(0x0008000000000000ULL);               /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);               /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);               /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);               /* max negative subnormal */

    /* --- Section 4: Normal boundary values (4) --- */
    emit(DBL_MIN);                               /* 2^-1022: smallest positive normal */
    emit(-DBL_MIN);                              /* -(2^-1022) */
    emit_u(0x0010000000000001ULL);               /* DBL_MIN + 1 ULP */
    emit(DBL_MAX);                               /* largest finite double */

    /* --- Section 5: Near-zero Taylor series path (10) --- */
    /* log1p(x) ~ x - x^2/2 + ... for |x| << 1; implementations switch here */
    emit_u(0x3e50000000000000ULL);               /* 2^-26: below fast-path threshold */
    emit_u(0xbe50000000000000ULL);               /* -(2^-26) */
    emit_u(0x3f00000000000000ULL);               /* 2^-15 */
    emit_u(0xbf00000000000000ULL);               /* -(2^-15) */
    emit_u(0x3fb0000000000000ULL);               /* 2^-4 = 0.0625 */
    emit_u(0xbfb0000000000000ULL);               /* -(2^-4) */
    emit(1.0e-10);                               /* small: Taylor path */
    emit(-1.0e-10);
    emit(1.0e-20);                               /* very small: log1p(x) ~ x */
    emit(-1.0e-20);

    /* --- Section 6: Near -1.0 divergence region (10) --- */
    /* log1p(x) -> -Inf as x -> -1 from above */
    emit_u(0xbfeffffffffffffcULL);               /* -1.0 + 4 ULP (x slightly above -1) */
    emit_u(0xbfeffffffffffff8ULL);               /* -1.0 + 8 ULP */
    emit_u(0xbfeffffffffffff0ULL);               /* -1.0 + 16 ULP */
    emit_u(0xbfefffffffffffc0ULL);               /* -1.0 + 64 ULP */
    emit_u(0xbfeffffffffffff2ULL);               /* -1.0 + a few ULP */
    emit(-0.9999999999);                         /* very close to -1 from above */
    emit(-0.999999999);
    emit(-0.99999999);
    emit(-0.9999999);
    emit(-0.999999);

    /* --- Section 7: Known mathematical values (12) --- */
    emit(1.0);                                   /* log1p(1) = log(2) ~ 0.693147 */
    emit_u(0x4005bf0a8b145769ULL);               /* e - 1 ~ 1.71828: log1p(e-1) = 1 */
    emit(0.5);                                   /* log1p(0.5) = log(1.5) */
    emit(-0.5);                                  /* log1p(-0.5) = log(0.5) = -ln2 */
    emit(9.0);                                   /* log1p(9) = log(10) ~ 2.302585 */
    emit(99.0);                                  /* log1p(99) = log(100) ~ 4.605170 */
    emit_u(0x3fe62e42fefa39efULL);               /* ln2 ~ 0.693147: log1p(ln2) */
    emit(2.0);                                   /* log1p(2) = log(3) ~ 1.098612 */
    emit(4.0);                                   /* log1p(4) = log(5) ~ 1.609438 */
    emit(-0.25);                                 /* log1p(-0.25) = log(0.75) */
    emit(-0.75);                                 /* log1p(-0.75) = log(0.25) = -2*ln2 */
    emit(0.25);                                  /* log1p(0.25) = log(1.25) */

    /* --- Section 8: Near 1.0 ULP density (8) --- */
    emit_u(0x3feffffffffffffULL);                /* 1.0 - 1 ULP = just below 1.0 */
    emit_u(0x3ff0000000000000ULL);               /* 1.0 exactly */
    emit_u(0x3ff0000000000001ULL);               /* 1.0 + 1 ULP */
    emit_u(0x3ff0000000000010ULL);               /* 1.0 + 16 ULP */
    emit_u(0x3feffffffffffffaULL);               /* 1.0 - 6 ULP */
    emit_u(0x3ff0000000000100ULL);               /* 1.0 + 256 ULP */
    emit_u(0x3feffffffffffff0ULL);               /* 1.0 - 16 ULP */
    emit_u(0x3ff0000000001000ULL);               /* 1.0 + larger offset */

    /* --- Section 9: Large positive values: log1p(x) ~ log(x) (10) --- */
    emit(10.0);
    emit(100.0);
    emit(1000.0);
    emit(1.0e6);
    emit(1.0e10);
    emit(1.0e50);
    emit(1.0e100);
    emit(1.0e200);
    emit(1.0e300);
    emit_u(0x7fefffffffffffffULL);               /* DBL_MAX: largest finite double */

    /* --- Section 10: Moderate range coverage (27) --- */
    /* Negative side: (-1, 0) in steps */
    emit(-0.9);
    emit(-0.8);
    emit(-0.7);
    emit(-0.6);
    emit(-0.4);
    emit(-0.3);
    emit(-0.2);
    emit(-0.1);
    emit(-0.01);
    emit(-0.001);
    /* Positive side: moderate values */
    emit(0.1);
    emit(0.2);
    emit(0.3);
    emit(0.4);
    emit(0.6);
    emit(0.7);
    emit(0.8);
    emit(0.9);
    emit(1.5);
    emit(2.5);
    emit(3.0);
    emit(5.0);
    emit(7.0);
    emit(15.0);
    emit(31.0);
    emit(63.0);
    emit(127.0);
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [-0.95, 100.0] in 200 steps */
static void test_sweep(void)
{
    double lo = -0.95;
    double hi = 100.0;
    int nsteps = 200;
    double step = (hi - lo) / (double)nsteps;

    /* [-0.95, 100.0] */
    for (int i = 0; i <= nsteps; i++)
        emit(lo + (double)i * step);

    /* [100.0, -0.95] (decreasing) */
    for (int i = 0; i <= nsteps; i++)
        emit(hi - (double)i * step);
}

/* 8. Sample [0, 0.1] with representative bit patterns */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3f847ae147ae147bULL, /* 0.01 */
        0x3f9eb851eb851eb8ULL, /* 0.03 */
        0x3fa999999999999aULL, /* 0.05 */
        0x3fb4cccccccccccdULL, /* 0.08 */
        0x3fb999999999999aULL, /* ~0.1 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

